import{_ as a,c as o,b0 as r,o as t}from"./chunks/framework.DIXa3MoD.js";const h=JSON.parse('{"title":"Privacy Policy","description":"","frontmatter":{},"headers":[],"relativePath":"en/privacy/index.md","filePath":"en/privacy/index.md","lastUpdated":1769153511000}'),i={name:"en/privacy/index.md"};function n(s,e,p,l,c,m){return t(),o("div",null,e[0]||(e[0]=[r('<h1 id="privacy-policy" tabindex="-1">Privacy Policy <a class="header-anchor" href="#privacy-policy" aria-label="Permalink to &quot;Privacy Policy&quot;">​</a></h1><p>(Revision date: July 16, 2022; Effective date: July 16, 2022)</p><p>Ham values and protects your personal privacy. Sometimes we need certain information to provide the services you request. This privacy statement explains how data is collected and used in these cases. This statement applies to all related services of the Ham app.</p><h3 id="collection-of-personal-information" tabindex="-1">Collection of personal information <a class="header-anchor" href="#collection-of-personal-information" aria-label="Permalink to &quot;Collection of personal information&quot;">​</a></h3><p>When we need information that can identify you (personal information) or contact you, we will ask for your consent.</p><p>Ham does not collect your personal information. However, to improve app performance or for usage statistics, your personal information may be shared with third parties. The third-party services used by Ham are:</p><p><strong>AMap Open Platform Location SDK</strong></p><p>Third-party name: AutoNavi Software Co., Ltd.</p><p>Purpose: Obtain location to display weather</p><p>Function type: Location and weather search information</p><p>Personal information involved: WLAN status information, location information</p><p>Privacy policy link: <a href="https://lbs.amap.com/pages/privacy/" target="_blank" rel="noreferrer">https://lbs.amap.com/pages/privacy/</a></p><br><p><strong>UMeng SDK</strong></p><p>Service type: Statistics and performance analysis</p><p>Personal information collected: Device information</p><p>Privacy policy link: <a href="https://www.umeng.com/page/policy" target="_blank" rel="noreferrer">https://www.umeng.com/page/policy</a></p><h3 id="control-of-personal-information" tabindex="-1">Control of personal information <a class="header-anchor" href="#control-of-personal-information" aria-label="Permalink to &quot;Control of personal information&quot;">​</a></h3><p>Ham will disclose your personal information only when required by law or consistent with Ham service terms or software license agreements, or when there is sufficient reason to believe disclosure is necessary to:</p><p>(a) comply with explicit legal requirements or applicable legal procedures for this app;</p><p>(b) comply with Ham service terms or software license agreements;</p><p>(c) protect Ham rights or property; and</p><p>(d) protect the personal safety of Ham staff, Ham product or service users, or the public in emergencies.</p><p>Ham will not share this information with third parties without permission, except for the situations listed in this statement.</p><h3 id="personal-information-security" tabindex="-1">Personal information security <a class="header-anchor" href="#personal-information-security" aria-label="Permalink to &quot;Personal information security&quot;">​</a></h3><p>We strictly protect the security of your personal information. We use various security technologies and procedures to prevent unauthorized access, use, or disclosure.</p><h3 id="disclaimer" tabindex="-1">Disclaimer <a class="header-anchor" href="#disclaimer" aria-label="Permalink to &quot;Disclaimer&quot;">​</a></h3><p>Ham does not assume any legal liability for the following matters:</p><p>Ham provides your personal information as required by law or by relevant government authorities;</p><p>Personal information leakage not caused by Ham;</p><p>Any disputes arising from third parties using your personal information in accordance with Ham service terms and the situations listed in this statement;</p><p>Temporary service interruption caused by hacker attacks, computer viruses, or government control;</p><p>Any consequences caused by force majeure;</p><p>Other exemptions stated in Ham service terms and this statement.</p><h3 id="revisions" tabindex="-1">Revisions <a class="header-anchor" href="#revisions" aria-label="Permalink to &quot;Revisions&quot;">​</a></h3><p>This privacy policy may be updated as needed. We recommend that users check the latest privacy policy online regularly. If any terms are updated in the future, we will not actively notify users. Updates will not be applied retroactively, and will not change how we handled previously collected data.</p>',36)]))}const u=a(i,[["render",n]]);export{h as __pageData,u as default};
